ALTER TABLE public.configuracion_empresa
ADD COLUMN IF NOT EXISTS texto_cae_conformidad_asistentes text NOT NULL DEFAULT '<p>Los asistentes firman con lo tratado en prueba de conformidad. Se recuerda que la ausencia a esta Reunión de Prevención supone falta de cumplimiento de la Ley 31/1995 de 8 noviembre de Prevención de Riesgos Laborables en su Artículo 24 sobre la Coordinación de actividades empresariales y con el Real Decreto 171/04. Se podrá convocar a los asistentes a reuniones alternas salvo causas justificadas. Se firmarán todas y cada una de las páginas y se entregará una copia digitalizada a cada uno de los asistentes. La no asistencia a la reunión debe implicar la designación a favor de otro asistente para que pueda aprobar el acta, o en caso contrario, quedará aceptada.</p>';

UPDATE public.configuracion_empresa
SET texto_cae_conformidad_asistentes = '<p>Los asistentes firman con lo tratado en prueba de conformidad. Se recuerda que la ausencia a esta Reunión de Prevención supone falta de cumplimiento de la Ley 31/1995 de 8 noviembre de Prevención de Riesgos Laborables en su Artículo 24 sobre la Coordinación de actividades empresariales y con el Real Decreto 171/04. Se podrá convocar a los asistentes a reuniones alternas salvo causas justificadas. Se firmarán todas y cada una de las páginas y se entregará una copia digitalizada a cada uno de los asistentes. La no asistencia a la reunión debe implicar la designación a favor de otro asistente para que pueda aprobar el acta, o en caso contrario, quedará aceptada.</p>'
WHERE texto_cae_conformidad_asistentes IS NULL OR texto_cae_conformidad_asistentes = '';